#include <bits/stdc++.h>
using namespace std;

const int N=1003;

bool compare(int a, int b)
{
    cout << "? " << a << ' ' << b << endl;
    bool t;
    cin >> t;
    return t;
}

int main(){
    int n;
    vector<int> g;
    scanf("%d",&n);
    g.push_back(0);
    g.push_back(1);
    for(int i=2;i<=n;i++){
        int l=0,r=i-1;
        while(l<r){
            int mid=l+r+1>>1;
            if(compare(g[mid],i))
                l=mid;
            else
                r=mid-1;
        }
        g.insert(g.begin()+l+1,i);
        //二分最后一个小于k的点下标在后面
    }
    printf("!");
    for(int i=1;i<=n;i++)
        printf(" %d",g[i]);
    return 0;
}
